styles.css:
.wp-travel-booknow-btns:hover, #wptravel-blocks-book-button button:hover,
.new-bottom-booking-container .wp-travel-booking__panel-bottom-new .right-info button.wp-travel-book {
    border-radius: 25px !important;
}
.booknow-btn-modal .wptrave-singlepage-initial-nextbtn button,
.booknow-btn-modal .wptravel-onepage-navigation-btn button{
    background: #00afe9;
    color: #fff;
    border: none;
    border-radius: 25px !important;
}
    .wptravel-onepage-navigation-btn #wp-travel-book-now, 
    .wptravel-book-your-trips.wp-travel-booknow-btns {
        padding: 10px 15px !important;
