        margin-right: 50px;
        font-weight: bold;
    }
    .swiper-button-prev:after, .swiper-rtl .swiper-button-next:after{
    font-size: 15px !important;
        border-radius: 50%;
        outline: 0;
        background: #fff;
        color: #000;
        padding: 20px 25px;
        margin-left: 50px;
        font-weight: bold;
    }
    .tmf-07-group .wp-block-latest-posts__list li:first-child{
        margin-bottom: 20px;
    }
