        position: absolute;
        left: 50%;
        bottom: 50%;
        transform: translate(-50%, 50%);
    }
    input[type="submit"] {
        background-color: #00afe9 !important;
        color: #fff !important;
        border-color: #00afe9 !important;
    }
    input[type="submit"]:hover {
        opacity: 0.8;
    }
    .error404 .wp-block-search__inside-wrapper .wp-block-search__input {
        background: #fff;
    }
