    }
    ul a:hover {
        color: #00afe9;
    }
    .wp-block-post-navigation-link a:hover {
        color: #00afe9;
    }
    .tmf-07-group img {
        border-radius: 10px;
    }
    .tmf-03-cover .tmf-title {
        display: none;
    }
    .tmf-03-cover:hover .tmf-title {
        display: block;
    }
    .wp-travel-checkout-section input[type="submit"] {
        padding: 10px 20px;
        font-size: 16px;
        font-weight: bold;
        display: inline-block;
        letter-spacing: 0.01em;
        position: relative;
        text-align: center;
        background-color: #00afe9;
        border: 2px solid #e5f8fc;
        color: #fff;
        border-radius: 50px;
        font-family: 'Raleway', sans-serif;
        -webkit-transition: all 0.3s ease-in-out;
        -moz-transition: all 0.3s ease-in-out;
        -ms-transition: all 0.3s ease-in-out;
        -o-transition: all 0.3s ease-in-out;
        transition: all 0.3s ease-in-out;
    }
    /* Start: navigation */
    .wp-block-query-pagination-next .wp-block-query-pagination-next-arrow {
        font-size: 16px;
        font-weight: bold;
        content: ">";
    }
    .wp-block-query-pagination-previous .wp-block-query-pagination-next-arrow {
        font-size: 16px;
        font-weight: bold;
        content: "<";
    }
    .wp-block-query-pagination-next-arrow {
        visibility: hidden;
        position: relative;
    }
    .wp-block-query-pagination-next-arrow::before {
        content: ">";
        visibility: visible;
        position: absolute;
        left: 0;
        font-size: 25px;
        font-weight: 600;
        color: #000;
        line-height: 1;
    }
    .wp-block-query-pagination-previous-arrow {
        visibility: hidden;
        position: relative;
    }
    .wp-block-query-pagination-previous-arrow::before {
        content: "<";
        visibility: visible;
        position: absolute;
        right: 0;
        font-size: 25px;
        font-weight: bold;
        color: #000;
        line-height: 1;
    }
    .wp-block-query-pagination {
        display: flex;
        justify-content: flex-start;
        align-items: center;
        gap: 10px;
    }
    .wp-block-query-pagination-numbers {
        display: flex;
        gap: 8px;
    }
    .page-numbers {
        height: 40px;
        width: 40px;
        display: flex;
        justify-content: center;
        align-items: center;
        background-color: #ffffff;
        color: #333;
        border: 1px solid #ffffff;
        border-radius: 4px;
        text-decoration: none;
        transition: background-color 0.3s ease, color 0.3s ease;
    }
    .page-numbers:hover {
        background-color: #00afe9;
        color: #fff !important;
    }
    .page-numbers.current {
        background-color: #00afe9;
        color: #fff;
        border: 1px solid #00afe9;
    }
    .wp-block-query-pagination-next,
    .wp-block-query-pagination-previous {
        height: 40px;
        width: 40px;
        display: flex;
        justify-content: center;
        align-items: center;
        background-color: #ffffff;
        color: #000000;
        border: 1px solid #ffffff;
        border-radius: 4px;
        text-decoration: none;
    }
    .wp-block-query-pagination-next:hover,
    .wp-block-query-pagination-previous:hover {
        background-color: #00afe9;
        color: #fff !important;
    }
    .wp-block-query-pagination-next-arrow {
        margin-left: 0px !important;
    }
    .wp-block-query-pagination-previous-arrow {
        margin-right: 0px !important;
    }
    .wp-block-query-pagination-next:hover .wp-block-query-pagination-next-arrow::before {
        color: #fff;
    }
    .wp-block-query-pagination-previous:hover .wp-block-query-pagination-previous-arrow::before {
        color: #fff;
    }
    /* End : navigation */
    .tmf-about-us-seemore:hover,
    .gp7-mf-about-us-seemore a:hover {
        background-color: #a5bac2 !important;
        color: #fff !important;
    }
