    .gp7-mf-about-us-seemore a {
        padding: 14px 35px;
        background-color: #e5f8fc !important;
        color: #00afe9;
        border-radius: 50px;
        text-align: left;
    }
    #wptravel-scroll-to-top {
        border: none !important;
        right: 40px !important;
        padding: 10px 20px !important;
    }
