        box-shadow: 0px 20px 40px 0px rgba(0, 0, 0, 0.3);
    }
    .tmf-04-cover::after {
        content: "";
        position: absolute;
        top: 0;
        left: 0;
        width: 100%;
        height: 100%;
        background: rgba(0, 0, 0, 0);
