        content: "\f067";
        font-family: "Font Awesome 5 Free";
        font-weight: 900;
        font-size: 25px;
        display: flex;
        align-items: center;
        justify-content: center;
        text-align: center;
        width: 35px;
        height: 35px;
        line-height: 35px;
        background: #fff;
        border-radius: 50%;
